import docJson from '../documentation.json';

const forbidden = new Set(['__proto__', 'constructor', 'prototype']);
const isValidCompodocJson =
  docJson !== null &&
  typeof docJson === 'object' &&
  !Array.isArray(docJson) &&
  'components' in docJson &&
  !Object.keys(docJson).some(k => forbidden.has(k));

if (isValidCompodocJson) {
  (globalThis as Record<string, unknown>)['__STORYBOOK_COMPODOC_JSON__'] = docJson;
}

const preview: Preview = {
  tags: ['autodocs'],
};

export default preview;

