const chunks = [];
process.stdin.on('data', d => chunks.push(d));
process.stdin.on('end', () => {
  const report = JSON.parse(chunks.join(''));
  const vulns = report.vulnerabilities ?? {};
  const highs = new Map();
  for (const [, vuln] of Object.entries(vulns)) {
    if (vuln.severity !== 'high' && vuln.severity !== 'critical') continue;
    for (const via of (vuln.via ?? [])) {
      if (typeof via === 'object' && via.url) {
        const m = via.url.match(/(GHSA-[a-z0-9-]+)/i);
        if (m) highs.set(m[1], { name: vuln.name, severity: via.severity, title: via.title, url: via.url });
      }
    }
  }
  console.log(JSON.stringify([...highs.entries()], null, 2));
});
