#!/usr/bin/env node
// Runs npm audit and fails only if NEW high/critical advisories appear beyond the
// accepted baseline. The baseline captures known advisories that cannot be fixed
// without breaking changes (see SECURITY.md for per-entry rationale).
import { execSync } from 'node:child_process';

const ACCEPTED = new Set([
  // lodash <=4.17.23 in @verdaccio/local-storage-legacy
  // Dev-only (local registry test tool). Fix requires verdaccio@5.28.0 (breaking).
  'GHSA-xxjr-mmjv-4gpg', // Prototype Pollution in _.unset / _.omit (moderate)
  'GHSA-r5fr-rjxr-66jc', // Code Injection via _.template (high)
  'GHSA-f23m-r3pf-42rh', // Prototype Pollution via array path bypass (moderate)

  // minimatch 7.0.0-7.4.7 in @verdaccio/local-storage-legacy
  // Dev-only. Fix requires verdaccio@5.28.0 (breaking).
  'GHSA-3ppc-4f35-3m26', // ReDoS via repeated wildcards (high)
  'GHSA-7r86-cg39-jmmj', // ReDoS matchOne() combinatorial backtracking (high)
  'GHSA-23c5-xmqv-rm74', // ReDoS nested *() extglobs (high)

  // picomatch 4.0.0-4.0.3 in @compodoc/compodoc
  // Fix requires @compodoc/compodoc@1.1.0 which drops signal-based component support.
  'GHSA-3v7f-55p6-f55p', // Method Injection in POSIX Character Classes (moderate)
  'GHSA-c2c7-rcm5-vvqj', // ReDoS via extglob quantifiers (high)
]);

let raw;
try {
  raw = execSync('npm audit --json', { encoding: 'utf8' });
} catch (err) {
  raw = err.stdout ?? '{}';
}

const report = JSON.parse(raw);
const vulnerabilities = report.vulnerabilities ?? {};
const newHighs = [];

for (const [, vuln] of Object.entries(vulnerabilities)) {
  for (const via of (vuln.via ?? [])) {
    if (typeof via !== 'object' || !via.url) {
      continue;
    }

    if (via.severity !== 'high' && via.severity !== 'critical') {
      continue;
    }

    const match = via.url.match(/(GHSA-[a-z0-9-]+)/i);

    if (!match) {
      continue;
    }

    const ghsa = match[1];

    if (!ACCEPTED.has(ghsa)) {
      newHighs.push({ package: vuln.name, ghsa, severity: via.severity, title: via.title });
    }
  }
}

if (newHighs.length > 0) {
  console.error('[ERROR] New high/critical advisories detected (not in accepted baseline):');

  for (const item of newHighs) {
    console.error(`  ${item.package}: ${item.ghsa} (${item.severity}) - ${item.title}`);
  }

  console.error('');
  console.error('Review SECURITY.md. If the advisory is accepted, add it to the ACCEPTED set');
  console.error('in scripts/audit-baseline.mjs with a documented rationale.');
  process.exit(1);
}

const total = report.metadata?.vulnerabilities ?? {};
console.log(
  `[OK] Audit baseline check passed. No new high/critical advisories.` +
  ` (${total.high ?? 0} accepted high, ${total.critical ?? 0} critical, ${total.moderate ?? 0} moderate)`
);

